198	// ---------------------------------------------------------------------------
199	// CheckboxList (roles and groups)
200	// ---------------------------------------------------------------------------
201	function CheckboxList({
202	  items,
203	  selected,
204	  onChange,
205	  emptyText,
206	  getLabel,
207	}: {
208	  items: { id: string }[];
209	  selected: string[];
210	  onChange: (ids: string[]) => void;
211	  emptyText: string;
212	  getLabel: (item: { id: string }) => string;
213	}) {
214	  function toggle(id: string) {
215	    onChange(
216	      selected.includes(id)
217	        ? selected.filter((x) => x !== id)
218	        : [...selected, id],
219	    );
220	  }
221	  return (
222	    <div
223	      style={{
224	        maxHeight: "140px",
225	        overflowY: "auto",
226	        border: "1px solid var(--io-border)",
227	        borderRadius: "var(--io-radius)",
228	        background: "var(--io-surface-sunken)",
229	      }}
230	    >
231	      {items.map((item) => (
232	        <label
233	          key={item.id}
234	          style={{
235	            display: "flex",
236	            alignItems: "center",
237	            gap: "8px",
238	            padding: "7px 10px",
239	            cursor: "pointer",
240	            fontSize: "13px",
241	            color: "var(--io-text-primary)",
242	            borderBottom: "1px solid var(--io-border-subtle)",
243	          }}
244	        >
245	          <input
246	            type="checkbox"
247	            checked={selected.includes(item.id)}
248	            onChange={() => toggle(item.id)}
249	            style={{ accentColor: "var(--io-accent)", flexShrink: 0 }}
250	          />
251	          {getLabel(item)}
252	        </label>
253	      ))}
254	      {items.length === 0 && (
255	        <div
256	          style={{
257	            padding: "12px",
258	            fontSize: "12px",
259	            color: "var(--io-text-muted)",
260	            textAlign: "center",
261	            fontStyle: "italic",
262	          }}
263	        >
264	          {emptyText}
265	        </div>
266	      )}
267	    </div>
268	  );
269	}
