521	  function resetForm() {
522	    setForm(CREATE_FORM_DEFAULTS);
523	    setDisplayManual(false);
524	    setFormError(null);
525	    setFieldErrors({});
526	  }
527	
528	  function setNameField(key: "first_name" | "last_name", value: string) {
