611	              }}
612	              placeholder="Jane Smith"
613	            />
614	          </Field>
615	          <Field
616	            span={6}
617	            label="Username"
618	            required
619	            error={fieldErrors.username}
620	          >
621	            <input
622	              style={{
623	                ...inputStyle,
624	                borderColor: fieldErrors.username
625	                  ? "var(--io-danger)"
626	                  : undefined,
627	              }}
628	              value={form.username}
629	              onChange={(e) => {
630	                setForm((f) => ({ ...f, username: e.target.value }));
631	                if (fieldErrors.username)
632	                  setFieldErrors((fe) => ({ ...fe, username: "" }));
633	              }}
634	              placeholder="jsmith"
635	              autoComplete="off"
636	            />
637	          </Field>
638	
639	          <Field span={6} label="Email" required error={fieldErrors.email}>
640	            <input
641	              type="email"
642	              style={{
643	                ...inputStyle,
644	                borderColor: fieldErrors.email ? "var(--io-danger)" : undefined,
645	              }}
646	              value={form.email}
647	              onChange={(e) => {
648	                setForm((f) => ({ ...f, email: e.target.value }));
649	                if (fieldErrors.email)
650	                  setFieldErrors((fe) => ({ ...fe, email: "" }));
651	              }}
652	              placeholder="jane@example.com"
653	            />
654	          </Field>
655	          <Field
656	            span={6}
657	            label="Mobile Number"
658	            hint="Optional — required only if SMS MFA or alerts are enabled for this user"
659	          >
660	            <input
661	              type="tel"
662	              style={inputStyle}
663	              value={form.phone_number}
664	              onChange={(e) =>
665	                setForm((f) => ({ ...f, phone_number: e.target.value }))
666	              }
667	              placeholder="+1 555 000 0000"
668	            />
669	          </Field>
670	
671	          <SectionHeader title="Security" />
672	
673	          <Field
674	            span={12}
675	            label="Password"
676	            required
677	            error={fieldErrors.password}
678	          >
679	            <input
680	              type="password"
681	              style={{
682	                ...inputStyle,
683	                borderColor: fieldErrors.password
684	                  ? "var(--io-danger)"
685	                  : undefined,
686	              }}
687	              value={form.password}
688	              onChange={(e) => {
689	                setForm((f) => ({ ...f, password: e.target.value }));
690	                if (fieldErrors.password)
691	                  setFieldErrors((fe) => ({ ...fe, password: "" }));
692	              }}
693	              autoComplete="new-password"
694	            />
695	          </Field>
696	
697	          <SectionHeader title="Access" />
698	
699	          <Field
700	            span={12}
701	            label="Roles"
702	            hint="Users with no roles assigned have no access to the system"
703	          >
704	            <CheckboxList
705	              items={roles}
