717	              items={groups}
718	              selected={form.group_ids ?? []}
719	              onChange={(ids) => setForm((f) => ({ ...f, group_ids: ids }))}
720	              emptyText="No groups defined"
721	              getLabel={(item) =>
722	                groups.find((g) => g.id === item.id)?.name ?? item.id
723	              }
724	            />
725	          </Field>
726	        </FormGrid>
727	
728	        <div
729	          style={{
730	            display: "flex",
731	            justifyContent: "flex-end",
732	            gap: "8px",
733	            marginTop: "28px",
734	            paddingTop: "20px",
735	            borderTop: "1px solid var(--io-border-subtle)",
736	          }}
737	        >
738	          <Dialog.Close asChild>
739	            <button type="button" style={btnSecondary} onClick={resetForm}>
740	              Cancel
741	            </button>
742	          </Dialog.Close>
743	          <button
