import React, { useState } from "react";
import ContextMenu from "../../shared/components/ContextMenu";
import { useContextMenu } from "../../shared/hooks/useContextMenu";
import * as Dialog from "@radix-ui/react-dialog";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  usersApi,
  User,
  UserDetail,
  CreateUserRequest,
  UpdateUserRequest,
} from "../../api/users";
import { rolesApi, Role } from "../../api/roles";
import { groupsApi, Group } from "../../api/groups";
import type { PaginatedResult } from "../../api/client";
import { ExportButton } from "../../shared/components/ExportDialog";
import {
  inputStyle,
  labelStyle,
  btnPrimary,
  btnSecondary,
  btnDanger,
  cellStyle,
} from "./settingsStyles";
import UserDetailDialog from "./UserDetail";

// ---------------------------------------------------------------------------
// Column definitions for users export
// ---------------------------------------------------------------------------
const USERS_COLUMNS = [
  { id: "id", label: "ID" },
  { id: "username", label: "Username" },
  { id: "email", label: "Email" },
  { id: "first_name", label: "First Name" },
  { id: "last_name", label: "Last Name" },
  { id: "display_name", label: "Display Name" },
  { id: "phone_number", label: "Mobile" },
  { id: "enabled", label: "Status" },
  { id: "auth_provider", label: "Auth Provider" },
  { id: "last_login_at", label: "Last Login" },
  { id: "created_at", label: "Created At" },
];

const USERS_DEFAULT_VISIBLE = [
  "username",
  "display_name",
  "email",
  "phone_number",
  "enabled",
  "auth_provider",
  "last_login_at",
];

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
function formatDate(iso: string | null): string {
  if (!iso) return "—";
  return new Date(iso).toLocaleDateString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

function userDisplayName(user: User): string {
  return (
    user.display_name ||
    [user.first_name, user.last_name].filter(Boolean).join(" ") ||
    user.full_name ||
    user.username
  );
}

// ---------------------------------------------------------------------------
// ErrorBanner
// ---------------------------------------------------------------------------
function ErrorBanner({ message }: { message: string }) {
  return (
    <div
      style={{
        background: "rgba(239,68,68,0.1)",
        border: "1px solid rgba(239,68,68,0.3)",
        borderRadius: "var(--io-radius)",
        padding: "10px 14px",
        color: "var(--io-danger)",
        fontSize: "13px",
        marginBottom: "16px",
      }}
    >
      {message}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Badge
// ---------------------------------------------------------------------------
function Badge({ label, color }: { label: string; color: string }) {
  return (
    <span
      style={{
        display: "inline-block",
        padding: "2px 8px",
        borderRadius: "100px",
        fontSize: "11px",
        fontWeight: 600,
        background: `${color}20`,
        color,
        border: `1px solid ${color}40`,
      }}
