// ---------------------------------------------------------------------------
// Toggle switch (used for the Enabled/Disabled field)
// ---------------------------------------------------------------------------
function ToggleSwitch({
  checked,
  onChange,
  label,
  hint,
}: {
  checked: boolean;
  onChange: (v: boolean) => void;
  label: string;
  hint?: string;
}) {
  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "12px 14px",
        background: "var(--io-surface-sunken)",
        border: "1px solid var(--io-border)",
        borderRadius: "var(--io-radius)",
        cursor: "pointer",
        userSelect: "none",
      }}
      onClick={() => onChange(!checked)}
    >
      <div>
        <div
          style={{
            fontSize: "13px",
            color: "var(--io-text-primary)",
            fontWeight: 500,
          }}
        >
          {label}
        </div>
        {hint && (
          <div
            style={{
              fontSize: "12px",
              color: "var(--io-text-muted)",
              marginTop: "2px",
            }}
          >
            {hint}
          </div>
        )}
      </div>
      <div
        style={{
          width: "40px",
          height: "22px",
          borderRadius: "11px",
          background: checked ? "var(--io-accent)" : "var(--io-border)",
          position: "relative",
          transition: "background 0.15s",
          flexShrink: 0,
        }}
      >
        <div
          style={{
            position: "absolute",
            top: "3px",
            left: checked ? "21px" : "3px",
            width: "16px",
            height: "16px",
            borderRadius: "50%",
            background: "white",
            transition: "left 0.15s",
            boxShadow: "0 1px 3px rgba(0,0,0,0.3)",
          }}
        />
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// CheckboxList (roles and groups)
// ---------------------------------------------------------------------------
function CheckboxList({
  items,
  selected,
  onChange,
  emptyText,
  getLabel,
}: {
  items: { id: string }[];
  selected: string[];
  onChange: (ids: string[]) => void;
  emptyText: string;
  getLabel: (item: { id: string }) => string;
}) {
  function toggle(id: string) {
    onChange(
      selected.includes(id)
        ? selected.filter((x) => x !== id)
        : [...selected, id],
    );
  }
  return (
    <div
      style={{
        maxHeight: "140px",
        overflowY: "auto",
        border: "1px solid var(--io-border)",
        borderRadius: "var(--io-radius)",
        background: "var(--io-surface-sunken)",
      }}
    >
      {items.map((item) => (
        <label
          key={item.id}
          style={{
            display: "flex",
            alignItems: "center",
            gap: "8px",
            padding: "7px 10px",
            cursor: "pointer",
            fontSize: "13px",
            color: "var(--io-text-primary)",
            borderBottom: "1px solid var(--io-border-subtle)",
          }}
        >
          <input
            type="checkbox"
            checked={selected.includes(item.id)}
            onChange={() => toggle(item.id)}
            style={{ accentColor: "var(--io-accent)", flexShrink: 0 }}
          />
          {getLabel(item)}
        </label>
      ))}
      {items.length === 0 && (
        <div
          style={{
            padding: "12px",
            fontSize: "12px",
            color: "var(--io-text-muted)",
            textAlign: "center",
            fontStyle: "italic",
          }}
        >
          {emptyText}
        </div>
      )}
    </div>
  );
}

