1	import React, { useRef } from "react";
2	
3	interface Tab {
4	  id: string;
5	  label: string;
6	}
7	
8	interface SettingsTabsProps {
9	  tabs: Tab[];
10	  activeTab: string;
11	  onTabChange: (id: string) => void;
12	  children?: React.ReactNode;
13	}
14	
15	export function SettingsTabs({
16	  tabs,
17	  activeTab,
18	  onTabChange,
19	  children,
20	}: SettingsTabsProps) {
21	  const tabListRef = useRef<HTMLDivElement>(null);
22	
23	  function handleKeyDown(e: React.KeyboardEvent, index: number) {
24	    let next = -1;
25	    if (e.key === "ArrowRight") next = (index + 1) % tabs.length;
26	    else if (e.key === "ArrowLeft")
27	      next = (index - 1 + tabs.length) % tabs.length;
28	    if (next >= 0) {
29	      e.preventDefault();
30	      onTabChange(tabs[next].id);
31	      const buttons =
32	        tabListRef.current?.querySelectorAll<HTMLButtonElement>('[role="tab"]');
33	      buttons?.[next]?.focus();
34	    }
35	  }
36	
37	  return (
38	    <div>
39	      <div
40	        ref={tabListRef}
41	        role="tablist"
42	        style={{
43	          display: "flex",
44	          borderBottom: "1px solid var(--io-border)",
45	          marginBottom: "20px",
46	        }}
47	      >
48	        {tabs.map((tab, index) => {
49	          const isActive = tab.id === activeTab;
50	          return (
51	            <button
52	              key={tab.id}
53	              role="tab"
54	              aria-selected={isActive}
55	              aria-controls={`tabpanel-${tab.id}`}
56	              id={`tab-${tab.id}`}
57	              tabIndex={isActive ? 0 : -1}
58	              onClick={() => onTabChange(tab.id)}
59	              onKeyDown={(e) => handleKeyDown(e, index)}
60	              style={{
61	                padding: "10px 16px",
62	                fontSize: "13px",
63	                fontWeight: isActive ? 600 : 400,
64	                background: "transparent",
65	                border: "none",
66	                borderBottom: isActive
67	                  ? "2px solid var(--io-accent)"
68	                  : "2px solid transparent",
69	                color: isActive
