import {
  useState,
  useEffect,
  useCallback,
  useRef,
  type CSSProperties,
} from "react";
import { flushSync } from "react-dom";
import {
  NavLink,
  Outlet,
  useNavigate,
  useLocation,
  useSearchParams,
} from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import {
  Monitor,
  Layers,
  LayoutDashboard,
  Bell,
  Settings as SettingsIcon,
  CheckSquare,
  BookOpen,
  MoreHorizontal,
  Download,
