333	  const [formError, setFormError] = useState<string | null>(null);
334	
335	  const groupDetailQuery = useQuery({
336	    queryKey: ["group-detail", group?.id],
337	    queryFn: async () => {
338	      if (!group) return null;
339	      const result = await groupsApi.get(group.id);
340	      if (!result.success) throw new Error(result.error.message);
341	      return result.data as GroupDetail;
342	    },
343	    enabled: !!group && open,
344	  });
345	
346	  React.useEffect(() => {
347	    if (groupDetailQuery.data) {
348	      setForm({
349	        name: groupDetailQuery.data.name,
350	        description: groupDetailQuery.data.description ?? "",
351	        role_ids: groupDetailQuery.data.roles.map((r) => r.id),
352	      });
353	    } else if (group && !groupDetailQuery.data) {
354	      setForm({
355	        name: group.name,
356	        description: group.description ?? "",
357	        role_ids: [],
358	      });
359	    }
360	  }, [group, groupDetailQuery.data]);
