// ---------------------------------------------------------------------------
// CreateGroupDialog
// ---------------------------------------------------------------------------
function CreateGroupDialog({
  open,
  onOpenChange,
  roles,
}: {
  open: boolean;
  onOpenChange: (v: boolean) => void;
  roles: Role[];
}) {
  const queryClient = useQueryClient();
  const [form, setForm] = useState<CreateGroupRequest>({
    name: "",
    description: "",
    role_ids: [],
  });
  const [formError, setFormError] = useState<string | null>(null);

  const mutation = useMutation({
    mutationFn: (req: CreateGroupRequest) => groupsApi.create(req),
    onSuccess: (result) => {
      if (!result.success) {
        setFormError(result.error.message);
        return;
      }
      queryClient.invalidateQueries({ queryKey: ["groups"] });
      onOpenChange(false);
      setForm({ name: "", description: "", role_ids: [] });
      setFormError(null);
    },
  });

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setFormError(null);
    mutation.mutate(form);
  }

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <ModalContent title="Create Group">
        {formError && <ErrorBanner message={formError} />}
        <form onSubmit={handleSubmit}>
          <div
            style={{ display: "flex", flexDirection: "column", gap: "14px" }}
          >
            <div>
              <label style={labelStyle}>Group Name *</label>
              <input
                style={inputStyle}
                value={form.name}
                onChange={(e) =>
                  setForm((f) => ({ ...f, name: e.target.value }))
                }
                placeholder="e.g. Operations Team"
                required
              />
            </div>
            <div>
              <label style={labelStyle}>Description</label>
              <input
                style={inputStyle}
                value={form.description ?? ""}
                onChange={(e) =>
                  setForm((f) => ({ ...f, description: e.target.value }))
                }
                placeholder="Optional description"
              />
            </div>
            <div>
              <label style={labelStyle}>
                Roles (members inherit all selected roles)
              </label>
              <RoleMultiSelect
                roles={roles}
                selected={form.role_ids ?? []}
                onChange={(ids) => setForm((f) => ({ ...f, role_ids: ids }))}
              />
            </div>
          </div>
          <div
            style={{
              display: "flex",
              justifyContent: "flex-end",
              gap: "8px",
              marginTop: "24px",
            }}
          >
            <Dialog.Close asChild>
              <button type="button" style={btnSecondary}>
                Cancel
              </button>
            </Dialog.Close>
            <button
              type="submit"
              style={btnPrimary}
              disabled={mutation.isPending}
            >
              {mutation.isPending ? "Creating..." : "Create Group"}
            </button>
          </div>
        </form>
      </ModalContent>
    </Dialog.Root>
  );
}

