// ---------------------------------------------------------------------------
// MenuItemRow — a single item in the menu (with optional submenu)
// ---------------------------------------------------------------------------

function MenuItemRow({
  item,
  onClose,
  zIndex,
}: {
  item: ContextMenuItem;
  onClose: () => void;
  zIndex: number;
}) {
  const [submenuOpen, setSubmenuOpen] = useState(false);
  const [submenuPos, setSubmenuPos] = useState({ x: 0, y: 0 });
  const rowRef = useRef<HTMLDivElement>(null);

  const hasSubmenu = item.children && item.children.length > 0;

  const handleActivate = () => {
    if (item.disabled) return;
    if (hasSubmenu) return; // submenu items don't fire onClick
    onClose();
    item.onClick?.();
  };

  const handleMouseEnter = (e: React.MouseEvent<HTMLDivElement>) => {
    if (item.disabled) return;
    (e.currentTarget as HTMLElement).style.background =
      "var(--io-accent-subtle)";
    (e.currentTarget as HTMLElement).focus();
    if (hasSubmenu) {
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      setSubmenuPos({ x: rect.right - 4, y: rect.top });
      setSubmenuOpen(true);
    }
  };

  const handleMouseLeave = (e: React.MouseEvent<HTMLDivElement>) => {
    (e.currentTarget as HTMLElement).style.background = "transparent";
    // Don't close submenu on mouse leave — it closes when parent menu closes
  };

  const textColor = item.danger
    ? "var(--io-alarm-urgent)"
    : item.disabled
      ? "var(--io-text-muted)"
      : "var(--io-text-primary)";

  return (
    <>
      <div
        ref={rowRef}
        role="menuitem"
        tabIndex={item.disabled ? -1 : 0}
        data-menu-item
        data-disabled={item.disabled ? "" : undefined}
        aria-disabled={item.disabled}
        aria-haspopup={hasSubmenu ? "menu" : undefined}
        aria-expanded={hasSubmenu ? submenuOpen : undefined}
        onClick={handleActivate}
        onKeyDown={(e) => {
          if (e.key === "Enter" || e.key === " ") {
            e.preventDefault();
            handleActivate();
          }
          if (e.key === "ArrowRight" && hasSubmenu) {
            e.preventDefault();
            if (rowRef.current) {
              const rect = rowRef.current.getBoundingClientRect();
              setSubmenuPos({ x: rect.right - 4, y: rect.top });
              setSubmenuOpen(true);
            }
          }
        }}
        onMouseEnter={handleMouseEnter}

